parameters.jsCode:
// ================================================================
// DETECT CHANGED PAGES
//
// This node compares each fetched page against the fingerprint
// stored in your Google Sheet, and keeps ONLY the pages that
// changed. Unchanged pages stop here — nothing else runs for them.
//
// You should not need to edit this node for normal use.
// ================================================================


// ---- STEP 1: Get both sides of the comparison -------------------
// "rows"    = the watchlist rows from your sheet (URL, Label, LastHash)
// "results" = the fetched page content, in the same order
const rows    = $('Read watchlist').all();
const results = $input.all();


// ---- STEP 2: A tiny "fingerprint" function ----------------------
// Turns the whole page text into a short code (a hash).
// Same text in = same code out, so if the code is different from
// last time, the page content changed. (This is an FNV-1a hash —
// the details don't matter for using the workflow.)
function contentHash(text) {
  let hash = 0x811c9dc5;
  for (let i = 0; i < text.length; i++) {
    hash = hash ^ text.charCodeAt(i);
    hash = Math.imul(hash, 0x01000193);
  }
  return (hash >>> 0).toString(16).padStart(8, '0');
}


// ---- STEP 3: Compare every page against its stored hash ---------
const changedPages = [];

for (let i = 0; i < results.length; i++) {
  const row    = rows[i] ? rows[i].json : {};
  const result = results[i].json;

  // If this page failed to fetch, skip it. We do NOT overwrite the
  // stored hash, so it will be checked normally again tomorrow.
  if (result.error) {
    continue;
  }

  // Pull the page text out of the Acrewity response.
  // (Different services return it in slightly different places,
  // so we check the common ones in order.)
  const pageText =
    result.result?.data?.content ||
    result.result?.markdown ||
    result.result?.content ||
    (typeof result.result === 'string' ? result.result : JSON.stringify(result.result || ''));

  if (!pageText) {
    continue;
  }

  // The actual comparison: new fingerprint vs the one in the sheet
  const newHash = contentHash(pageText);
  const oldHash = String(row.LastHash || '').trim();

  if (newHash !== oldHash) {
    changedPages.push({
      json: {
        URL: row.URL,
        Label: row.Label || row.URL,
        LastHash: newHash,            // written back to the sheet
        firstRun: oldHash === ''      // true = first time seeing this page
      }
    });
  }
}


// ---- STEP 4: Pass on only the changed pages ----------------------
// If nothing changed, this returns an empty list and the digest
// email is simply not sent today.
return changedPages;

